const q = $input.first().json.query || {};
const year = parseInt(q.year) || new Date().getFullYear();
const month = (q.month !== undefined) ? parseInt(q.month) : new Date().getMonth();
const service = (q.service || '').toLowerCase();

const DURATIONS = {
  'portfolio-model': 2, 'maternity': 2, 'boudoir': 3,
  'family': 3, 'couple': 3, 'business': 2, 'real-estate': 2,
  'wedding': 10, 'wedding-creative': 4, 'event': 10,
  'pet': 2, 'product': 3
};
const duration = DURATIONS[service] || 2;
const timeMin = new Date(year, month, 1).toISOString();
const timeMax = new Date(year, month + 1, 0, 23, 59, 59).toISOString();

return [{ json: { year, month, service, duration, timeMin, timeMax } }];

const events = ($input.first().json.items || []);
const { year, month, duration } = $('Paraméterek').first().json;

const START = 8, END = 20, BUFFER = 0.5;
const daysInMonth = new Date(year, month + 1, 0).getDate();
const today = new Date(); today.setHours(0, 0, 0, 0);
const tomorrow = new Date(today); tomorrow.setDate(tomorrow.getDate() + 1);
const pad = n => String(n).padStart(2, '0');

const availableDays = {};

for (let d = 1; d <= daysInMonth; d++) {
  const date = new Date(year, month, d);
  if (date < today) continue;
  const dateStr = `${year}-${pad(month + 1)}-${pad(d)}`;
  const slots = [];

  for (let h = START; h <= END - duration; h++) {
    const slotStart = new Date(year, month, d, h, 0);
    const slotEnd = new Date(slotStart.getTime() + duration * 3600000);

    const free = !events.some(ev => {
      if (!ev.start) return false;
      if (!ev.start.dateTime) return ev.start.date === dateStr;
      const evS = new Date(ev.start.dateTime);
      const evE = new Date(ev.end.dateTime);
      return slotStart < new Date(evE.getTime() + BUFFER * 3600000)
          && slotEnd   > new Date(evS.getTime() - BUFFER * 3600000);
    });

    if (free) slots.push(`${h}:00`);
  }

  if (slots.length > 0) availableDays[dateStr] = slots;
}

let suggested = null;
for (const [ds, slots] of Object.entries(availableDays)) {
  if (new Date(ds) >= tomorrow) {
    suggested = { date: ds, time: slots[Math.floor(slots.length / 2)] };
    break;
  }
}

return [{ json: { availableDays, suggested, duration } }];
